#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=1000005;
vector<int> g[N];
ll dp[N],dep[N],siz[N],n;
void dfs(int u,int f)
{
	siz[u]=1;
	dep[u]=dep[f]+1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v!=f)
		{
			dfs(v,u);
			siz[u]+=siz[v];
		}
	}
}
void dfs2(int u,int f)
{
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v!=f)
		{
			dp[v]=dp[u]+n-2*siz[v];
			dfs2(v,u);
		}
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dep[0]=-1;
	dfs(1,0);
	for(int i=1;i<=n;i++)
	{
		dp[1]+=dep[i];
	}
	dfs2(1,0);
	ll mx=-0x3f3f3f3f,id;
	for(int i=1;i<=n;i++)
	{
		if(dp[i]>mx)
		{
			mx=dp[i];
			id=i;
		}
	}
	cout<<id;
	return 0;
}
